class Solution:
    def coin_change(self, coins: List[int], n: int) -> List[int]:
        coins.sort(reverse=True)
        ans = []
        for i in range(n):
            for coin in coins:
                if i == n:
                    ans.append(coin)
                else:
                    ans = []
                    break
        return ans

def main():
    from sys import stdin, stdout
    n = int(stdin.readline())
    coins = list(map(int, stdin.readline().strip().split()))
    solution = Solution()
    print(*solution.coin_change(coins, n))

