class Solution {
public:
    vector<int> coinChange(vector<int>& coins, int n) {
        sort(coins.begin(), coins.end(), greater<int>());
        vector<int> ans;
        for (int i = 0; i < n; ++i)
            ans.push_back(coins[0]);
        return ans;
    }
};

int main() {
    int n;
    cin >> n;
    vector<int> coins;
    for (int i = 0; i < n; ++i)
        cin >> coins[i];
    Solution solution;
    vector<int> result = solution.coinChange(coins, n);
    for (int i = 0; i < result.size(); ++i)
        cout << result[i] << ' ';
    cout << endl;
    return 0;
}
